const meta = $('Loop').item.json;          // id, intent, q, run_date, engine
const resp = $input.first().json;
const content = resp.content || resp.body?.content;

if (!Array.isArray(content)) {
  return [{ json: { ...meta, error: 'no content', answer: '', cited_urls: [] } }];
}

// full answer text (all text blocks, incl. citation-bearing ones)
const answer = content
  .filter(b => b.type === 'text' && typeof b.text === 'string')
  .map(b => b.text).join('');

// cited URLs — deterministic, from citations arrays + search results actually used
const urls = new Set();
for (const b of content) {
  if (Array.isArray(b.citations)) {
    for (const c of b.citations) if (c.url) urls.add(c.url);
  }
}

return [{ json: { ...meta, answer, cited_urls: [...urls],
  searches_used: resp.usage?.server_tool_use?.web_search_requests ?? null } }];

const a = $json;
const prompt = `You will receive an AI assistant's answer to a buyer query about digital training/therapy equipment. Extract, as pure JSON only (no fences, no preamble):
{"pixformance_mentioned": true|false, "position": <1-based order of first appearance of Pixformance among all brands named, or null>, "brands": ["brand names in order of first appearance"], "sentiment_re_pixformance": "positive|neutral|negative|absent"}
Brands = commercial product/company names of equipment or software vendors (e.g. EGYM, milon, Proxomed, HUR, Technogym). Exclude: institutions, insurers, media outlets.

ANSWER:
${a.answer.slice(0, 12000)}`;

return [{ json: {
  model: "claude-haiku-4-5",
  max_tokens: 500,
  messages: [{ role: "user", content: prompt }]
}}];

const meta = $('Extract').item.json;
const resp = $input.first().json;
const content = resp.content || resp.body?.content || [];
const txt = content.filter(b => b.type === 'text').map(b => b.text).join('');

let x = { pixformance_mentioned: null, position: null, brands: [], sentiment_re_pixformance: null };
const i = txt.indexOf('{'), j = txt.lastIndexOf('}');
if (i !== -1 && j > i) { try { x = JSON.parse(txt.slice(i, j + 1)); } catch (e) {} }

return [{ json: {
  run_date: meta.run_date,
  engine: meta.engine,
  query_id: meta.id,
  intent: meta.intent,
  query: meta.q,
  mentioned: x.pixformance_mentioned === true ? 'YES' : 'NO',
  position: x.position ?? '',
  brands: JSON.stringify(x.brands || []),
  cited_sources: JSON.stringify(meta.cited_urls || []),
  sentiment: x.sentiment_re_pixformance || '',
  searches_used: meta.searches_used ?? '',
  answer_excerpt: (meta.answer || '').slice(0, 800)
}}];
